class Solution:
    def countCompleteSubstrings(self, word, k):
        n = len(word)
        count = 0
        for i in range(n):
            freq = {}
            for j in range(i, n):
                if j > i and abs(ord(word[j]) - ord(word[j - 1])) > 2:
                    break
                ch = word[j]
                freq[ch] = freq.get(ch, 0) + 1
                if all(v == k for v in freq.values()):
                    count += 1
        return count

