class Solution:
    def countCompleteSubstrings(self, word, k):
        n = len(word)
        blocks = []
        start = 0
        for i in range(1, n + 1):
            if i == n or abs(ord(word[i]) - ord(word[i - 1])) > 2:
                blocks.append(word[start:i])
                start = i
        total = 0
        for block in blocks:
            total += self._count_in_block(block, k)
        return total

    def _count_in_block(self, s, k):
        n = len(s)
        count = 0
        for d in range(1, 27):
            length = d * k
            if length > n:
                break
            freq = [0] * 26
            distinct = 0
            good = 0
            for i in range(n):
                c = ord(s[i]) - 97
                if freq[c] == 0:
                    distinct += 1
                if freq[c] == k:
                    good -= 1
                freq[c] += 1
                if freq[c] == k:
                    good += 1
                if i >= length:
                    rc = ord(s[i - length]) - 97
                    if freq[rc] == k:
                        good -= 1
                    freq[rc] -= 1
                    if freq[rc] == 0:
                        distinct -= 1
                    elif freq[rc] == k:
                        good += 1
                if i >= length - 1:
                    if distinct == d and good == d:
                        count += 1
        return count

