function countInBlock(s, k) {
    const n = s.length;
    let count = 0;
    for (let d = 1; d <= 26; d++) {
        const length = d * k;
        if (length > n) break;
        const freq = new Array(26).fill(0);
        let distinct = 0;
        let good = 0;
        for (let i = 0; i < n; i++) {
            const c = s.charCodeAt(i) - 97;
            if (freq[c] === 0) distinct += 1;
            if (freq[c] === k) good -= 1;
            freq[c] += 1;
            if (freq[c] === k) good += 1;
            if (i >= length) {
                const rc = s.charCodeAt(i - length) - 97;
                if (freq[rc] === k) good -= 1;
                freq[rc] -= 1;
                if (freq[rc] === 0) distinct -= 1;
                else if (freq[rc] === k) good += 1;
            }
            if (i >= length - 1) {
                if (distinct === d && good === d) count += 1;
            }
        }
    }
    return count;
}

var countCompleteSubstrings = function(word, k) {
    const n = word.length;
    let total = 0;
    let start = 0;
    for (let i = 1; i <= n; i++) {
        if (i === n || Math.abs(word.charCodeAt(i) - word.charCodeAt(i - 1)) > 2) {
            total += countInBlock(word.slice(start, i), k);
            start = i;
        }
    }
    return total;
};
